books_src = var_call_ahAFDnZZvsNY9gpfSDyfmgbj
if isinstance(books_src, str):
    with open(books_src, 'r', encoding='utf-8') as f:
        books = json.load(f)
else:
    books = books_src

avg5 = var_call_wFvndhx83zJHoz3RDeg1CUJj
avg5_df = pd.DataFrame(avg5)
if not avg5_df.empty:
    avg5_df['purchase_id_num'] = avg5_df['purchase_id'].str.extract(r'(\d+)').astype(int)

books_df = pd.DataFrame(books)
# English-language filter from details text
books_df['is_english'] = books_df['details'].fillna('').str.contains(r'\bEnglish\b', case=False, regex=True)
